{
var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);

    var displaceMap = inputs.Length > 1 && inputs[1] != null ? inputs[1]! : null;

    var scaleX = GetFloat(parameters, "offsetX", 0.1f);
    var scaleY = GetFloat(parameters, "offsetY", 0.1f);
    var channel = GetChoice(parameters, "channel", "luminance");
    var wrap = GetBool(parameters, "wrap", true);
    var invert = GetBool(parameters, "invert", false);

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);

    output.ParallelForEachPixel((x, y) =>
    {
        var u = (float)x / size;
        var v = (float)y / size;

        // Sample displacement
        var disp = 0f;
        if (displaceMap != null)
        {
            var du = (float)x / size;
            var dv = (float)y / size;
            var dx = (int)(du * (displaceMap.Width - 1));
            var dy = (int)(dv * (displaceMap.Height - 1));
            dx = Math.Clamp(dx, 0, displaceMap.Width - 1);
            dy = Math.Clamp(dy, 0, displaceMap.Height - 1);
            var (rd, gd, bd, _) = displaceMap.GetPixel(dx, dy);

            disp = channel switch
            {
                "red" => rd,
                "green" => gd,
                "blue" => bd,
                _ => rd * 0.299f + gd * 0.587f + bd * 0.114f
            };
        }

        if (invert) disp = 1f - disp;

        // Offset coordinates
        var offX = u + (disp - 0.5f) * scaleX;
        var offY = v + (disp - 0.5f) * scaleY;

        // Sample input with bilinear interpolation
        float r, g, b, a;
        if (wrap)
        {
            offX = offX - MathF.Floor(offX);
            offY = offY - MathF.Floor(offY);
        }

        var sx = offX * (input.Width - 1);
        var sy = offY * (input.Height - 1);

        if (wrap)
        {
            (r, g, b, a) = SampleBilinearWrap(input, sx, sy);
        }
        else
        {
            (r, g, b, a) = SampleBilinearClamp(input, sx, sy);
        }

        output.SetPixel(x, y, r, g, b, a);
    });

    return output;

private static (float, float, float, float) SampleBilinearWrap(PixelBuffer buffer, float sx, float sy)
{
    var w = buffer.Width;
    var h = buffer.Height;

    // Wrap coordinates
    sx = Mod(sx, w - 1);
    sy = Mod(sy, h - 1);

    var x0 = (int)sx;
    var y0 = (int)sy;
    var x1 = (x0 + 1) % (w - 1);
    var y1 = (y0 + 1) % (h - 1);
    var fx = sx - x0;
    var fy = sy - y0;

    var (r00, g00, b00, a00) = buffer.GetPixel(x0, y0);
    var (r10, g10, b10, a10) = buffer.GetPixel(x1, y0);
    var (r01, g01, b01, a01) = buffer.GetPixel(x0, y1);
    var (r11, g11, b11, a11) = buffer.GetPixel(x1, y1);

    return (
        Lerp(Lerp(r00, r10, fx), Lerp(r01, r11, fx), fy),
        Lerp(Lerp(g00, g10, fx), Lerp(g01, g11, fx), fy),
        Lerp(Lerp(b00, b10, fx), Lerp(b01, b11, fx), fy),
        Lerp(Lerp(a00, a10, fx), Lerp(a01, a11, fx), fy)
    );
}

private static (float, float, float, float) SampleBilinearClamp(PixelBuffer buffer, float sx, float sy)
{
    var w = buffer.Width - 1;
    var h = buffer.Height - 1;
    sx = Math.Clamp(sx, 0f, w);
    sy = Math.Clamp(sy, 0f, h);

    var x0 = (int)sx;
    var y0 = (int)sy;
    var x1 = Math.Min(x0 + 1, w);
    var y1 = Math.Min(y0 + 1, h);
    var fx = sx - x0;
    var fy = sy - y0;

    var (r00, g00, b00, a00) = buffer.GetPixel(x0, y0);
    var (r10, g10, b10, a10) = buffer.GetPixel(x1, y0);
    var (r01, g01, b01, a01) = buffer.GetPixel(x0, y1);
    var (r11, g11, b11, a11) = buffer.GetPixel(x1, y1);

    return (
        Lerp(Lerp(r00, r10, fx), Lerp(r01, r11, fx), fy),
        Lerp(Lerp(g00, g10, fx), Lerp(g01, g11, fx), fy),
        Lerp(Lerp(b00, b10, fx), Lerp(b01, b11, fx), fy),
        Lerp(Lerp(a00, a10, fx), Lerp(a01, a11, fx), fy)
    );
}

private static float Mod(float a, float b) => ((a % b) + b) % b;
}
